from fastapi import FastAPI, WebSocket, Request
from fastapi.templating import Jinja2Templates
from fastapi.staticfiles import StaticFiles
import json
import asyncio
import psutil
import time
from datetime import datetime
import random

app = FastAPI(title="System Dashboard")
app.mount("/static", StaticFiles(directory="static"), name="static")
templates = Jinja2Templates(directory="templates")

class MetricsCollector:
    @staticmethod
    def get_system_metrics():
        return {
            "cpu_percent": psutil.cpu_percent(interval=1),
            "memory": psutil.virtual_memory()._asdict(),
            "disk": psutil.disk_usage('/')._asdict(),
            "network": psutil.net_io_counters()._asdict(),
            "timestamp": datetime.now().isoformat()
        }

    @staticmethod
    def get_app_metrics():
        # Simulated app metrics - replace with your actual metrics
        return {
            "active_users": random.randint(150, 300),
            "requests_per_minute": random.randint(800, 1200),
            "error_rate": round(random.uniform(0.1, 2.5), 2),
            "response_time": round(random.uniform(120, 350), 1)
        }

@app.get("/")
async def dashboard(request: Request):
    return templates.TemplateResponse("dashboard.html", {"request": request})

@app.websocket("/ws")
async def websocket_endpoint(websocket: WebSocket):
    await websocket.accept()
    try:
        while True:
            metrics = {
                "system": MetricsCollector.get_system_metrics(),
                "app": MetricsCollector.get_app_metrics()
            }
            await websocket.send_text(json.dumps(metrics))
            await asyncio.sleep(2)  # Update every 2 seconds
    except Exception as e:
