import pandas as pd
import logging
from pathlib import Path
from typing import Dict, List, Optional, Union, Callable
from dataclasses import dataclass

@dataclass
class ValidationResult:
    is_valid: bool
    errors: List[str]
    warnings: List[str]

class CSVProcessor:
    def __init__(
        self,
        required_headers: List[str],
        optional_headers: Optional[List[str]] = None,
        dtype_mapping: Optional[Dict[str, str]] = None,
        validators: Optional[Dict[str, Callable]] = None
    ):
        self.required_headers = required_headers
        self.optional_headers = optional_headers or []
        self.dtype_mapping = dtype_mapping or {}
        self.validators = validators or {}
        self.logger = logging.getLogger(__name__)

    def process_csv(
        self,
        file_path: Union[str, Path],
        encoding: str = 'utf-8',
        delimiter: str = ',',
        skip_bad_rows: bool = True
    ) -> pd.DataFrame:
        """
        Process CSV file with validation and error handling.

        Args:
            file_path: Path to CSV file
            encoding: File encoding
            delimiter: CSV delimiter
            skip_bad_rows: Whether to skip invalid rows or raise exception

        Returns:
            Cleaned pandas DataFrame

        Raises:
            FileNotFoundError: If file doesn't exist
            ValueError: If validation fails and skip_bad_rows=False
        """
        file_path = Path(file_path)

        # Validate file exists
        if not file_path.exists():
            raise FileNotFoundError(f"CSV file not found: {file_path}")

        try:
            # Read CSV with error handling
            df = pd.read_csv(
                file_path,
                encoding=encoding,
                delimiter=delimiter,
                dtype=str,  # Read as strings first for validation
                na_values=['', 'NULL', 'null', 'N/A', 'n/a'],
                keep_default_na=True
            )

            self.logger.info(f"Read CSV with {len(df)} rows, {len(df.columns)} columns")

            # Validate headers
            validation_result = self._validate_headers(df.columns.tolist())
            if not validation_result.is_valid:
                error_msg = f"Header validation failed: {'; '.join(validation_result.errors)}"
                if not skip_bad_rows:
                    raise ValueError(error_msg)
                self.logger.error(error_msg)
                return pd.DataFrame()

            # Log warnings
            for warning in validation_result.warnings:
                self.logger.warning(warning)

            # Clean and validate data
            cleaned_df = self._clean_dataframe(df, skip_bad_rows)

            self.logger.info(f"Processing complete: {len(cleaned_df)} valid rows")
            return cleaned_df

        except pd.errors.EmptyDataError:
            self.logger.error(f"CSV file is empty: {file_path}")
            return pd.DataFrame()

        except pd.errors.ParserError as e:
            self.logger.error(f"CSV parsing error: {e}")
            if not skip_bad_rows:
                raise ValueError(f"CSV parsing failed: {e}")
            return pd.DataFrame()

        except UnicodeDecodeError as e:
            self.logger.error(f"Encoding error with {encoding}: {e}")
            raise ValueError(f"File encoding error. Try different encoding.")

        except Exception as e:
            self.logger.error(f"Unexpected error processing CSV: {e}")
            raise

    def _validate_headers(self, headers: List[str]) -> ValidationResult:
        """Validate CSV headers against requirements."""
        errors = []
        warnings = []

        # Check for required headers
        missing_required = set(self.required_headers) - set(headers)
        if missing_required:
            errors.append(f"Missing required headers: {list(missing_required)}")

        # Check for unexpected headers
        expected_headers = set(self.required_headers + self.optional_headers)
        unexpected = set(headers) - expected_headers
        if unexpected:
            warnings.append(f"Unexpected headers found: {list(unexpected)}")

        # Check for duplicates
        duplicates = [h for h in headers if headers.count(h) > 1]
        if duplicates:
            errors.append(f"Duplicate headers: {list(set(duplicates))}")

        return ValidationResult(
            is_valid=len(errors) == 0,
            errors=errors,
            warnings=warnings
        )

    def _clean_dataframe(self, df: pd.DataFrame, skip_bad_rows: bool) -> pd.DataFrame:
        """Clean and validate dataframe rows."""
        original_count = len(df)

        # Remove completely empty rows
        df = df.dropna(how='all')

        # Apply data type conversions
        for column, dtype in self.dtype_mapping.items():
            if column in df.columns:
                df[column] = self._convert_column_dtype(df[column], dtype, column)

        # Apply custom validators
        if self.validators:
            valid_mask = pd.Series([True] * len(df))

            for column, validator in self.validators.items():
                if column in df.columns:
                    try:
                        column_valid = df[column].apply(validator)
                        valid_mask &= column_valid

                        invalid_count = (~column_valid).sum()
                        if invalid_count > 0:
                            self.logger.warning(
                                f"Column '{column}': {invalid_count} invalid values"
                            )
                    except Exception as e:
                        self.logger.error(f"Validator error for column '{column}': {e}")
                        if not skip_bad_rows:
                            raise

            if skip_bad_rows:
                df = df[valid_mask]
            elif not valid_mask.all():
                invalid_count = (~valid_mask).sum()
                raise ValueError(f"Validation failed for {invalid_count} rows")

        # Log cleaning results
        removed_count = original_count - len(df)
        if removed_count > 0:
            self.logger.info(f"Removed {removed_count} invalid/empty rows")

        return df

    def _convert_column_dtype(self, series: pd.Series, target_dtype: str, column_name: str) -> pd.Series:
        """Convert column to target dtype with error handling."""
        try:
            if target_dtype == 'int':
                return pd.to_numeric(series, errors='coerce').astype('Int64')
            elif target_dtype == 'float':
                return pd.to_numeric(series, errors='coerce')
            elif target_dtype == 'datetime':
                return pd.to_datetime(series, errors='coerce')
            elif target_dtype == 'bool':
                return series.map({'true': True, 'false': False, '1': True, '0': False})
            else:
                return series.astype(str)
        except Exception as e:
            self.logger.warning(f"Type conversion failed for column '{column_name}': {e}")
            return series

